import{_ as s}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as a,a as e,e as l,r as o,o as r}from"./app-MOk6SBbl.js";const i={};function d(p,t){const n=o("Mermaid");return r(),a("div",null,[t[0]||(t[0]=e('<h2 id="引言" tabindex="-1"><a class="header-anchor" href="#引言"><span>引言</span></a></h2><p>Explain 告诉你用了索引，但为什么选这个索引呢？同一条 SQL 换个参数就走了完全不同的索引——这不是玄学，而是优化器在背后做了复杂的代价计算。当你只能看到执行计划的结果，却不知道优化器为什么做出这个选择时，排查就走进了死胡同。</p><p>好在 MySQL 提供了一个好用的工具——<code>optimizer_trace</code>（优化器追踪），可以帮你查看优化器生成执行计划的完整过程，包括访问表的方法、各种开销计算、各种转换等。读完本文你将掌握：</p><ul><li><strong>optimizer_trace 的开启与解读</strong>：从配置到输出的完整流程</li><li><strong>索引选择过程的代价分析</strong>：为什么同一条 SQL 不同参数走了不同的索引</li><li><strong>生产环境安全使用指南</strong>：如何在不影响线上服务的前提下分析执行计划</li></ul><h2 id="optimizer-trace-配置查看" tabindex="-1"><a class="header-anchor" href="#optimizer-trace-配置查看"><span>optimizer_trace 配置查看</span></a></h2><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> VARIABLES <span class="token operator">LIKE</span> <span class="token string">&#39;%optimizer_trace%&#39;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出参数详解：</p><table><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>optimizer_trace</strong></td><td style="text-align:left;">主配置，enabled 的 on 表示开启，off 表示关闭；one_line 表示是否展示成一行</td></tr><tr><td style="text-align:left;"><strong>optimizer_trace_features</strong></td><td style="text-align:left;">表示优化器的可选特性，包括贪心搜索、范围优化等</td></tr><tr><td style="text-align:left;"><strong>optimizer_trace_limit</strong></td><td style="text-align:left;">优化器追踪最大显示数目，默认是 1 条</td></tr><tr><td style="text-align:left;"><strong>optimizer_trace_max_mem_size</strong></td><td style="text-align:left;">优化器追踪占用的最大内存容量</td></tr><tr><td style="text-align:left;"><strong>optimizer_trace_offset</strong></td><td style="text-align:left;">显示的第一个优化器追踪的偏移量</td></tr></tbody></table><blockquote><p><strong>💡 核心提示</strong>：<code>optimizer_trace_max_mem_size</code> 默认值是 1MB（1048576 字节）。对于复杂 SQL，优化过程生成的追踪信息可能超出限制，超出部分会被截断并在 <code>MISSING_BYTES_BEYOND_MAX_MEM_SIZE</code> 列中显示被截断的字节数。如果分析大 SQL，可适当调大此值。</p></blockquote><h2 id="开启-optimizer-trace" tabindex="-1"><a class="header-anchor" href="#开启-optimizer-trace"><span>开启 optimizer_trace</span></a></h2><p><strong>optimizer_trace</strong> 默认是关闭的，可以使用命令手动开启：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SET</span> optimizer_trace <span class="token operator">=</span> <span class="token string">&quot;enabled=on&quot;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p><strong>注意</strong>：开启 optimizer_trace 会带来一定的性能开销，因为它需要记录优化器内部的所有决策过程。建议仅在诊断时临时开启，分析完毕后立即关闭：<code>SET optimizer_trace = &quot;enabled=off&quot;;</code></p></blockquote><h2 id="线上问题复现-为什么选错索引" tabindex="-1"><a class="header-anchor" href="#线上问题复现-为什么选错索引"><span>线上问题复现：为什么选错索引？</span></a></h2><p>先造点数据备用，创建一张用户表：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">`</span>user<span class="token punctuation">`</span></span> <span class="token punctuation">(</span>\n  <span class="token identifier"><span class="token punctuation">`</span>id<span class="token punctuation">`</span></span> <span class="token keyword">int</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">AUTO_INCREMENT</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;主键&#39;</span><span class="token punctuation">,</span>\n  <span class="token identifier"><span class="token punctuation">`</span>name<span class="token punctuation">`</span></span> <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;姓名&#39;</span><span class="token punctuation">,</span>\n  <span class="token identifier"><span class="token punctuation">`</span>gender<span class="token punctuation">`</span></span> <span class="token keyword">tinyint</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;性别&#39;</span><span class="token punctuation">,</span>\n  <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">`</span>id<span class="token punctuation">`</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n  <span class="token keyword">KEY</span> <span class="token identifier"><span class="token punctuation">`</span>idx_name<span class="token punctuation">`</span></span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">`</span>name<span class="token punctuation">`</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n  <span class="token keyword">KEY</span> <span class="token identifier"><span class="token punctuation">`</span>idx_gender_name<span class="token punctuation">`</span></span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">`</span>gender<span class="token punctuation">`</span></span><span class="token punctuation">,</span> <span class="token identifier"><span class="token punctuation">`</span>name<span class="token punctuation">`</span></span><span class="token punctuation">)</span>\n<span class="token punctuation">)</span> <span class="token keyword">ENGINE</span><span class="token operator">=</span><span class="token keyword">InnoDB</span> <span class="token keyword">COMMENT</span><span class="token operator">=</span><span class="token string">&#39;用户表&#39;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>创建了两个索引，分别是 <code>idx_name(name)</code> 和 <code>idx_gender_name(gender, name)</code>。</p><h3 id="第一次查询" tabindex="-1"><a class="header-anchor" href="#第一次查询"><span>第一次查询</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> <span class="token keyword">WHERE</span> gender <span class="token operator">=</span> <span class="token number">0</span> <span class="token operator">AND</span> name <span class="token operator">=</span> <span class="token string">&#39;一灯&#39;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>EXPLAIN 结果显示，优先使用了 <code>idx_gender_name</code> 的联合索引，因为 WHERE 条件中刚好有 <code>gender</code> 和 <code>name</code> 两个字段，与联合索引的最左前缀完美匹配。</p><h3 id="第二次查询-换个参数" tabindex="-1"><a class="header-anchor" href="#第二次查询-换个参数"><span>第二次查询（换个参数）</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> <span class="token keyword">WHERE</span> gender <span class="token operator">=</span> <span class="token number">0</span> <span class="token operator">AND</span> name <span class="token operator">=</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这次竟然使用了 <code>idx_name</code> 上的索引！同一条 SQL 因为传参不同，而使用了不同的索引。到这里，使用现有工具已经无法分析：MySQL 优化器为什么使用了 <code>idx_name</code> 而没有使用 <code>idx_gender_name</code>？只能请今天的主角——<strong>optimizer_trace</strong> 出场了。</p><h2 id="使用-optimizer-trace-分析" tabindex="-1"><a class="header-anchor" href="#使用-optimizer-trace-分析"><span>使用 optimizer_trace 分析</span></a></h2><p>使用 <strong>optimizer_trace</strong> 查看优化器的选择过程：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> information_schema<span class="token punctuation">.</span>OPTIMIZER_TRACE<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出结果共有 4 列：</p><table><thead><tr><th style="text-align:left;">列名</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>QUERY</strong></td><td style="text-align:left;">我们执行的查询语句</td></tr><tr><td style="text-align:left;"><strong>TRACE</strong></td><td style="text-align:left;">优化器生成执行计划的过程（重点关注）</td></tr><tr><td style="text-align:left;"><strong>MISSING_BYTES_BEYOND_MAX_MEM_SIZE</strong></td><td style="text-align:left;">被截断的优化过程信息字节数</td></tr><tr><td style="text-align:left;"><strong>INSUFFICIENT_PRIVILEGES</strong></td><td style="text-align:left;">是否有权限查看优化过程，0 表示有权限，1 表示没有</td></tr></tbody></table><h3 id="解读-trace-列-索引选择过程" tabindex="-1"><a class="header-anchor" href="#解读-trace-列-索引选择过程"><span>解读 TRACE 列：索引选择过程</span></a></h3><p>TRACE 列的 JSON 内容量很大，我们重点分析 <strong>range_scan_alternatives</strong> 部分，这部分展示了优化器的索引选择过程。该部分包含以下关键字段：</p><table><thead><tr><th style="text-align:left;">字段</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>index</strong></td><td style="text-align:left;">索引名称</td></tr><tr><td style="text-align:left;"><strong>ranges</strong></td><td style="text-align:left;">查询范围</td></tr><tr><td style="text-align:left;"><strong>index_dives_for_eq_ranges</strong></td><td style="text-align:left;">是否用到索引潜水的优化逻辑</td></tr><tr><td style="text-align:left;"><strong>rowid_ordered</strong></td><td style="text-align:left;">结果是否按主键排序</td></tr><tr><td style="text-align:left;"><strong>using_mrr</strong></td><td style="text-align:left;">是否使用 Multi-Range Read 优化</td></tr><tr><td style="text-align:left;"><strong>index_only</strong></td><td style="text-align:left;">是否使用了覆盖索引</td></tr><tr><td style="text-align:left;"><strong>in_memory</strong></td><td style="text-align:left;">使用内存大小</td></tr><tr><td style="text-align:left;"><strong>rows</strong></td><td style="text-align:left;">预估扫描行数</td></tr><tr><td style="text-align:left;"><strong>cost</strong></td><td style="text-align:left;">预估成本大小，值越低越好</td></tr><tr><td style="text-align:left;"><strong>chosen</strong></td><td style="text-align:left;">是否被选中</td></tr><tr><td style="text-align:left;"><strong>cause</strong></td><td style="text-align:left;">未被选择的原因，cost 过高即成本过高</td></tr></tbody></table>',31)),l(n,{id:"mermaid-292",code:""}),t[1]||(t[1]=e('<blockquote><p><strong>💡 核心提示</strong>：优化器选择索引的依据是 <strong>cost（代价）</strong>，代价 = I/O 成本 + CPU 成本。优化器会估算使用每个索引需要扫描的行数（rows），再乘以单位行的 I/O 和 CPU 成本，得到总 cost。<strong>cost 值越低的索引越可能被选中</strong>，但这不一定是我们直觉上认为&quot;最优&quot;的索引——因为优化器依赖统计信息的准确性。</p></blockquote><p>从输出结果中可以看到，优化器最终选择了使用 <code>idx_name</code> 索引，而 <code>idx_gender_name</code> 索引因为 <strong>cost 过高</strong> 没有被选择。这背后的原因可能是：优化器根据表的统计信息（如索引选择性、数据分布）估算出 <code>idx_name</code> 能过滤出更少的行数，从而认为 <code>idx_name</code> 的代价更低。</p><h2 id="生产环境避坑指南" tabindex="-1"><a class="header-anchor" href="#生产环境避坑指南"><span>生产环境避坑指南</span></a></h2><table><thead><tr><th style="text-align:left;">坑位</th><th style="text-align:left;">现象</th><th style="text-align:left;">解决方案</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>内存限制导致信息截断</strong></td><td style="text-align:left;"><code>MISSING_BYTES_BEYOND_MAX_MEM_SIZE</code> 有值，trace 信息不完整</td><td style="text-align:left;">调大 <code>optimizer_trace_max_mem_size</code>（如设置为 4MB），重新执行查询</td></tr><tr><td style="text-align:left;"><strong>生产环境长时间开启</strong></td><td style="text-align:left;">性能开销累积，影响线上 QPS</td><td style="text-align:left;">仅在诊断会话中临时开启，分析后立即关闭：<code>SET optimizer_trace = &quot;enabled=off&quot;</code></td></tr><tr><td style="text-align:left;"><strong>统计信息不准确</strong></td><td style="text-align:left;">优化器基于过期的统计信息做出错误选择</td><td style="text-align:left;">定期执行 <code>ANALYZE TABLE</code> 更新统计信息，确保优化器的代价估算准确</td></tr><tr><td style="text-align:left;"><strong>trace 输出难以理解</strong></td><td style="text-align:left;">JSON 格式嵌套深，字段繁多</td><td style="text-align:left;">关注 <code>range_scan_alternatives</code> 和 <code>cost</code> 关键字段，使用 JSON 格式化工具查看</td></tr><tr><td style="text-align:left;"><strong>参数绑定导致索引变化</strong></td><td style="text-align:left;">同一 SQL 不同参数走了不同索引</td><td style="text-align:left;">这是正常现象——优化器根据具体参数值选择性不同索引。可使用 <code>EXPLAIN FORMAT=JSON</code> 或 optimizer_trace 逐一分析</td></tr><tr><td style="text-align:left;"><strong>忘记关闭 optimizer_trace</strong></td><td style="text-align:left;">会话保持开启状态影响后续查询性能</td><td style="text-align:left;">养成分析完毕后立即关闭的习惯，或使用 <code>SET optimizer_trace = &quot;enabled=off&quot;;</code> 作为诊断脚本的结尾</td></tr></tbody></table><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h2><table><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">用途</th><th style="text-align:left;">精度</th><th style="text-align:left;">推荐场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>EXPLAIN</strong></td><td style="text-align:left;">查看执行计划结果</td><td style="text-align:left;">索引、连接类型、扫描行数</td><td style="text-align:left;">日常 SQL 优化</td></tr><tr><td style="text-align:left;"><strong>EXPLAIN FORMAT=JSON</strong></td><td style="text-align:left;">查看更详细的执行计划</td><td style="text-align:left;">成本估算、过滤条件</td><td style="text-align:left;">深入分析执行计划</td></tr><tr><td style="text-align:left;"><strong>optimizer_trace</strong></td><td style="text-align:left;">查看优化器完整决策过程</td><td style="text-align:left;">索引选择过程、代价计算细节</td><td style="text-align:left;">定位索引选错原因</td></tr></tbody></table><h3 id="行动清单" tabindex="-1"><a class="header-anchor" href="#行动清单"><span>行动清单</span></a></h3><ol><li><strong>诊断时临时开启</strong>：<code>SET optimizer_trace = &quot;enabled=on&quot;</code>，用完立即关闭。</li><li><strong>调大内存限制</strong>：遇到信息截断时，先执行 <code>SET optimizer_trace_max_mem_size = 4194304</code>。</li><li><strong>重点关注 range_scan_alternatives</strong>：这是索引选择的核心分析区域，对比各索引的 cost。</li><li><strong>定期更新统计信息</strong>：执行 <code>ANALYZE TABLE</code> 确保优化器的统计信息是最新的。</li><li><strong>理解代价模型</strong>：优化器基于 cost 做选择，不要主观认为&quot;一定应该走某个索引&quot;。</li><li><strong>扩展阅读</strong>：推荐《MySQL 技术内幕：InnoDB 存储引擎》第 6 章&quot;查询优化&quot;和 MySQL 官方文档 &quot;The Optimizer Trace&quot;。</li></ol>',8))])}const u=s(i,[["render",d],["__file","MySQL链路追踪.html.vue"]]),m=JSON.parse('{"path":"/mysql/MySQL%E9%93%BE%E8%B7%AF%E8%BF%BD%E8%B8%AA.html","title":"","lang":"zh-CN","frontmatter":{"description":"引言 Explain 告诉你用了索引，但为什么选这个索引呢？同一条 SQL 换个参数就走了完全不同的索引——这不是玄学，而是优化器在背后做了复杂的代价计算。当你只能看到执行计划的结果，却不知道优化器为什么做出这个选择时，排查就走进了死胡同。 好在 MySQL 提供了一个好用的工具——optimizer_trace（优化器追踪），可以帮你查看优化器生成执...","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/mysql/MySQL%E9%93%BE%E8%B7%AF%E8%BF%BD%E8%B8%AA.html"}],["meta",{"property":"og:site_name","content":"Java八股文网"}],["meta",{"property":"og:description","content":"引言 Explain 告诉你用了索引，但为什么选这个索引呢？同一条 SQL 换个参数就走了完全不同的索引——这不是玄学，而是优化器在背后做了复杂的代价计算。当你只能看到执行计划的结果，却不知道优化器为什么做出这个选择时，排查就走进了死胡同。 好在 MySQL 提供了一个好用的工具——optimizer_trace（优化器追踪），可以帮你查看优化器生成执..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-04-18T07:28:17.000Z"}],["meta",{"property":"article:author","content":"Mr.Hope"}],["meta",{"property":"article:modified_time","content":"2026-04-18T07:28:17.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-04-18T07:28:17.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.Hope\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"引言","slug":"引言","link":"#引言","children":[]},{"level":2,"title":"optimizer_trace 配置查看","slug":"optimizer-trace-配置查看","link":"#optimizer-trace-配置查看","children":[]},{"level":2,"title":"开启 optimizer_trace","slug":"开启-optimizer-trace","link":"#开启-optimizer-trace","children":[]},{"level":2,"title":"线上问题复现：为什么选错索引？","slug":"线上问题复现-为什么选错索引","link":"#线上问题复现-为什么选错索引","children":[{"level":3,"title":"第一次查询","slug":"第一次查询","link":"#第一次查询","children":[]},{"level":3,"title":"第二次查询（换个参数）","slug":"第二次查询-换个参数","link":"#第二次查询-换个参数","children":[]}]},{"level":2,"title":"使用 optimizer_trace 分析","slug":"使用-optimizer-trace-分析","link":"#使用-optimizer-trace-分析","children":[{"level":3,"title":"解读 TRACE 列：索引选择过程","slug":"解读-trace-列-索引选择过程","link":"#解读-trace-列-索引选择过程","children":[]}]},{"level":2,"title":"生产环境避坑指南","slug":"生产环境避坑指南","link":"#生产环境避坑指南","children":[]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[{"level":3,"title":"行动清单","slug":"行动清单","link":"#行动清单","children":[]}]}],"git":{"createdTime":1745907928000,"updatedTime":1776497297000,"contributors":[{"name":"Yideng","email":"oointer@163.com","commits":2}]},"readingTime":{"minutes":6.27,"words":1882},"filePathRelative":"mysql/MySQL链路追踪.md","localizedDate":"2025年4月29日","autoDesc":true}');export{u as comp,m as data};
